mapper.select:
SELECT p.place_id, p.name, p.category, p.image_url, p.description AS summary, COALESCE(fav_agg.like_count, 0) AS like_count, tag_agg.tags_csv FROM place p LEFT JOIN ( SELECT pt.place_id, GROUP_CONCAT(t.name ORDER BY t.name SEPARATOR ',') AS tags_csv FROM place_tag pt JOIN tag t ON pt.tag_id = t.tag_id WHERE pt.can_use = 1 AND t.can_use = 1 GROUP BY pt.place_id ) tag_agg ON p.place_id = tag_agg.place_id LEFT JOIN ( SELECT place_id, COUNT(*) AS like_count FROM place_favorite GROUP BY place_id ) fav_agg ON p.place_id = fav_agg.place_id
p.deleted_at IS NULL
AND p.category = #{category}
AND p.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.place_id DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM place_favorite
WHERE user_id = #{userId}
AND place_id = #{placeId}

